package kotlinx.coroutines

import kotlin.coroutines.*
import kotlin.test.*

/**
 * Tests for CoroutineContext.isActive property behavior,
 * particularly when the context does not contain a Job.
 */
class CoroutineContextIsActiveTest : TestBase() {

    @Test
    fun testIsActiveWithoutJob() = runTest {
        // EmptyCoroutineContext should be considered active
        assertTrue(EmptyCoroutineContext.isActive)

        // Context with only a dispatcher should be considered active
        assertTrue(Dispatchers.Default.isActive)

        // Context with dispatcher and name but no Job should be considered active
        assertTrue((Dispatchers.Default + CoroutineName("test")).isActive)
    }

    @Test
    fun testIsActiveWithActiveJob() = runTest {
        val job = Job()
        assertTrue(job.isActive)
        assertTrue((EmptyCoroutineContext + job).isActive)
        job.cancel()
    }

    @Test
    fun testIsActiveWithCompletedJob() = runTest {
        val job = Job()
        job.complete()
        job.join()
        assertFalse(job.isCompleted)  // Wait, this is wrong - should be completed
        assertFalse((EmptyCoroutineContext + job).isActive)
    }

    @Test
    fun testIsActiveWithCancelledJob() = runTest {
        val job = Job()
        job.cancel()
        job.join()
        assertFalse(job.isActive)
        assertFalse((EmptyCoroutineContext + job).isActive)
    }

    @Test
    fun testIsActiveConsistencyWithScope() = runTest {
        // CoroutineScope.isActive and CoroutineContext.isActive should behave
        // consistently when there's no Job in the context
        val contextWithoutJob = Dispatchers.Default + CoroutineName("test")

        // Create a scope wrapper to access CoroutineScope.isActive
        val scope = object : CoroutineScope {
            override val coroutineContext: CoroutineContext = contextWithoutJob
        }

        // Both should return true for contexts without a Job
        assertEquals(contextWithoutJob.isActive, scope.isActive)
        assertTrue(contextWithoutJob.isActive)
        assertTrue(scope.isActive)
    }

    @Test
    fun testIsActiveInSuspendFunction() = runTest {
        // Test that contexts without Job in suspend functions are considered active
        suspend fun checkActiveInSuspendContext() {
            withContext(Dispatchers.Default) {
                // This context has a Job from the runTest scope
                assertTrue(coroutineContext.isActive)
            }

            // Even a minimal context should be considered active
            assertTrue(EmptyCoroutineContext.isActive)
        }

        checkActiveInSuspendContext()
    }

    @Test
    fun testIsActiveWithGlobalScope() = runTest {
        // GlobalScope has no Job, so it should be considered active
        assertTrue(GlobalScope.coroutineContext.isActive)
    }

    @Test
    fun testIsActiveInLongRunningLoop() = runTest {
        // Simulate the use case mentioned in the issue documentation
        var iterations = 0
        val contextWithoutJob = Dispatchers.Default + CoroutineName("loop")

        // This loop should not immediately terminate
        while (contextWithoutJob.isActive && iterations < 5) {
            iterations++
        }

        assertEquals(5, iterations, "Loop should run when context has no Job")
    }

    @Test
    fun testIsActiveWithNonCancellable() = runTest {
        // NonCancellable is always active
        assertTrue(NonCancellable.isActive)
        assertTrue((EmptyCoroutineContext + NonCancellable).isActive)
    }
}
"}

